26	PRIVATE_NAMESPACE_BEGIN
27	
28	struct MemoryPass : public Pass {
29		MemoryPass() : Pass("memory", "translate memories to basic cells") { }
30		void help() override
31		{
32			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
33			log("\n");
34			log("    memory [-norom] [-nomap] [-nordff] [-nowiden] [-nosat] [-memx] [-no-rw-check] [-bram <bram_rules>] [selection]\n");
35			log("\n");
36			log("This pass calls all the other memory_* passes in a useful order:\n");
37			log("\n");
38			log("    opt_mem\n");
39			log("    opt_mem_priority\n");
40			log("    opt_mem_feedback\n");
41			log("    memory_bmux2rom                     (skipped if called with -norom)\n");
42			log("    memory_dff [-no-rw-check]           (skipped if called with -nordff or -memx)\n");
43			log("    opt_clean\n");
44			log("    memory_share [-nowiden] [-nosat]\n");
45			log("    opt_mem_widen\n");
46			log("    memory_memx                         (when called with -memx)\n");
47			log("    opt_clean\n");
48			log("    memory_collect\n");
49			log("    memory_bram -rules <bram_rules>     (when called with -bram)\n");
50			log("    memory_map                          (skipped if called with -nomap)\n");
51			log("\n");
52			log("This converts memories to word-wide DFFs and address decoders\n");
53			log("or multiport memory blocks if called with the -nomap option.\n");
54			log("\n");
55		}
56		void execute(std::vector<std::string> args, RTLIL::Design *design) override
57		{
58			bool flag_norom = false;
59			bool flag_nomap = false;
60			bool flag_nordff = false;
61			bool flag_memx = false;
62			string memory_dff_opts;
63			string memory_bram_opts;
64			string memory_share_opts;
65	
66			log_header(design, "Executing MEMORY pass.\n");
67			log_push();
68	
69			size_t argidx;
70			for (argidx = 1; argidx < args.size(); argidx++) {
71				if (args[argidx] == "-norom") {
72					flag_norom = true;
73					continue;
74				}
75				if (args[argidx] == "-nomap") {
76					flag_nomap = true;
77					continue;
78				}
79				if (args[argidx] == "-nordff") {
80					flag_nordff = true;
81					continue;
82				}
83				if (args[argidx] == "-memx") {
84					flag_nordff = true;
85					flag_memx = true;
86					continue;
87				}
88				if (args[argidx] == "-nowiden") {
89					memory_share_opts += " -nowiden";
90					continue;
91				}
92				if (args[argidx] == "-nosat") {
93					memory_share_opts += " -nosat";
94					continue;
95				}
96				if (args[argidx] == "-no-rw-check") {
97					memory_dff_opts += " -no-rw-check";
98					continue;
99				}
100				if (argidx+1 < args.size() && args[argidx] == "-bram") {
101					memory_bram_opts += " -rules " + args[++argidx];
102					continue;
103				}
104				break;
105			}
106			extra_args(args, argidx, design);
107	
108			Pass::call(design, "opt_mem");
109			Pass::call(design, "opt_mem_priority");
110			Pass::call(design, "opt_mem_feedback");
111			if (!flag_norom)
112				Pass::call(design, "memory_bmux2rom");
113			if (!flag_nordff)
114				Pass::call(design, "memory_dff" + memory_dff_opts);
115			Pass::call(design, "opt_clean");
116			Pass::call(design, "memory_share" + memory_share_opts);
117			Pass::call(design, "opt_mem_widen");
118			if (flag_memx)
119				Pass::call(design, "memory_memx");
120			Pass::call(design, "opt_clean");
121			Pass::call(design, "memory_collect");
122	
123			if (!memory_bram_opts.empty())
124				Pass::call(design, "memory_bram" + memory_bram_opts);
125	
126			if (!flag_nomap)
127				Pass::call(design, "memory_map");
128	
129			log_pop();
130		}
131	} MemoryPass;
132	
133	PRIVATE_NAMESPACE_END
