1	/*
2	 *  yosys -- Yosys Open SYnthesis Suite
3	 *
4	 *  Copyright (C) 2012  Claire Xenia Wolf <claire@yosyshq.com>
5	 *
6	 *  Permission to use, copy, modify, and/or distribute this software for any
7	 *  purpose with or without fee is hereby granted, provided that the above
8	 *  copyright notice and this permission notice appear in all copies.
9	 *
10	 *  THE SOFTWARE IS PROVIDED "AS IS" AND THE AUTHOR DISCLAIMS ALL WARRANTIES
11	 *  WITH REGARD TO THIS SOFTWARE INCLUDING ALL IMPLIED WARRANTIES OF
12	 *  MERCHANTABILITY AND FITNESS. IN NO EVENT SHALL THE AUTHOR BE LIABLE FOR
13	 *  ANY SPECIAL, DIRECT, INDIRECT, OR CONSEQUENTIAL DAMAGES OR ANY DAMAGES
14	 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
15	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
16	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
17	 *
18	 */
19	
20	#include "kernel/register.h"
21	#include "kernel/log.h"
22	#include "kernel/mem.h"
23	#include <sstream>
24	#include <set>
25	#include <stdlib.h>
26	
27	USING_YOSYS_NAMESPACE
28	PRIVATE_NAMESPACE_BEGIN
29	
30	struct MemoryMapWorker
31	{
32		bool attr_icase = false;
33		bool rom_only = false;
34		bool keepdc = false;
35		bool formal = false;
36		dict<RTLIL::IdString, std::vector<RTLIL::Const>> attributes;
37	
38		RTLIL::Design *design;
39		RTLIL::Module *module;
40		SigMap sigmap;
41		FfInitVals initvals;
42	
43		std::map<std::pair<RTLIL::SigSpec, RTLIL::SigSpec>, RTLIL::SigBit> decoder_cache;
44	
45		MemoryMapWorker(RTLIL::Design *design, RTLIL::Module *module) : design(design), module(module), sigmap(module), initvals(&sigmap, module) {}
46	
47		std::string map_case(std::string value) const
48		{
49			if (attr_icase) {
50				for (char &c : value)
51					c = tolower(c);
52			}
53			return value;
54		}
55	
56		RTLIL::Const map_case(RTLIL::Const value) const
57		{
58			if (value.flags & RTLIL::CONST_FLAG_STRING)
59				return map_case(value.decode_string());
60			return value;
61		}
62	
63		std::string genid(RTLIL::IdString name, std::string token1 = "", int i = -1, std::string token2 = "", int j = -1, std::string token3 = "", int k = -1, std::string token4 = "")
64		{
65			std::stringstream sstr;
66			sstr << "$memory" << name.str() << token1;
67	
68			if (i >= 0)
69				sstr << "[" << i << "]";
70	
71			sstr << token2;
72	
73			if (j >= 0)
74				sstr << "[" << j << "]";
75	
76			sstr << token3;
77	
78			if (k >= 0)
79				sstr << "[" << k << "]";
80	
81			sstr << token4 << "$" << (autoidx++);
82			return sstr.str();
83		}
84	
85		RTLIL::Wire *addr_decode(RTLIL::SigSpec addr_sig, RTLIL::SigSpec addr_val)
86		{
87			std::pair<RTLIL::SigSpec, RTLIL::SigSpec> key(addr_sig, addr_val);
88			log_assert(GetSize(addr_sig) == GetSize(addr_val));
89	
90			if (decoder_cache.count(key) == 0) {
91				if (GetSize(addr_sig) < 2) {
92					decoder_cache[key] = module->Eq(NEW_ID, addr_sig, addr_val);
93				} else {
94					int split_at = GetSize(addr_sig) / 2;
95					RTLIL::SigBit left_eq = addr_decode(addr_sig.extract(0, split_at), addr_val.extract(0, split_at));
96					RTLIL::SigBit right_eq = addr_decode(addr_sig.extract(split_at, GetSize(addr_sig) - split_at), addr_val.extract(split_at, GetSize(addr_val) - split_at));
97					decoder_cache[key] = module->And(NEW_ID, left_eq, right_eq);
98				}
99			}
100	
101			RTLIL::SigBit bit = decoder_cache.at(key);
102			log_assert(bit.wire != nullptr && GetSize(bit.wire) == 1);
103			return bit.wire;
104		}
105	
106		void handle_memory(Mem &mem)
107		{
108			std::set<int> static_ports;
109			std::map<int, RTLIL::SigSpec> static_cells_map;
110	
111			SigSpec init_data = mem.get_init_data();
112	
113			if (!mem.wr_ports.empty() && rom_only)
114				return;
115	
116			// check if attributes allow us to infer FFRAM for this memory
117			for (const auto &attr : attributes) {
118				if (mem.attributes.count(attr.first)) {
119					const auto &cell_attr = mem.attributes[attr.first];
120					if (attr.second.empty()) {
121						log("Not mapping memory %s in module %s (attribute %s is set).\n",
122								mem.memid.c_str(), module->name.c_str(), attr.first.c_str());
123						return;
124					}
125	
126					bool found = false;
127					for (auto &value : attr.second) {
128						if (map_case(cell_attr) == map_case(value)) {
129							found = true;
130							break;
131						}
132					}
133					if (!found) {
134						if (cell_attr.flags & RTLIL::CONST_FLAG_STRING) {
135							log("Not mapping memory %s in module %s (attribute %s is set to \"%s\").\n",
136									mem.memid.c_str(), module->name.c_str(), attr.first.c_str(), cell_attr.decode_string().c_str());
137						} else {
138							log("Not mapping memory %s in module %s (attribute %s is set to %d).\n",
139									mem.memid.c_str(), module->name.c_str(), attr.first.c_str(), cell_attr.as_int());
140						}
141						return;
142					}
143				}
144			}
145	
146			// delete unused memory cell
147			if (mem.rd_ports.empty()) {
148				mem.remove();
149				return;
150			}
151	
152			// all write ports must share the same clock
153			RTLIL::SigSpec refclock;
154			bool refclock_pol = false;
155			bool async_wr = false;
156			bool static_only = true;
157			for (int i = 0; i < GetSize(mem.wr_ports); i++) {
158				auto &port = mem.wr_ports[i];
159				if (port.en.is_fully_const() && !port.en.as_bool()) {
160					static_ports.insert(i);
161					continue;
162				}
163				if (!port.clk_enable) {
164					if (port.addr.is_fully_const() && port.en.is_fully_ones()) {
165						for (int sub = 0; sub < (1 << port.wide_log2); sub++)
166							static_cells_map[port.addr.as_int() + sub] = port.data.extract(sub * mem.width, mem.width);
167						static_ports.insert(i);
168						continue;
169					}
170					static_only = false;
171					if (GetSize(refclock) != 0)
172						log("Not mapping memory %s in module %s (mixed clocked and async write ports).\n",
173								mem.memid.c_str(), module->name.c_str());
174					if (!formal)
175						log("Not mapping memory %s in module %s (write port %d has no clock).\n",
176									mem.memid.c_str(), module->name.c_str(), i);
177					async_wr = true;
178					continue;
179				}
180				static_only = false;
181				if (async_wr)
182					log("Not mapping memory %s in module %s (mixed clocked and async write ports).\n",
183							mem.memid.c_str(), module->name.c_str());
184				if (refclock.size() == 0) {
185					refclock = port.clk;
186					refclock_pol = port.clk_polarity;
187				}
188				if (port.clk != refclock || port.clk_polarity != refclock_pol) {
189					log("Not mapping memory %s in module %s (write clock %d is incompatible with other clocks).\n",
190							mem.memid.c_str(), module->name.c_str(), i);
191					return;
192				}
193			}
194	
195			log("Mapping memory %s in module %s:\n", mem.memid, module->name);
196	
197			int abits = ceil_log2(mem.size);
198			std::vector<RTLIL::SigSpec> data_reg_in(1 << abits);
199			std::vector<RTLIL::SigSpec> data_reg_out(1 << abits);
200	
201			std::vector<RTLIL::SigSpec> &data_read = async_wr ? data_reg_in : data_reg_out;
202	
203			int count_static = 0;
204	
205			for (int i = 0; i < mem.size; i++)
206			{
207				int addr = i + mem.start_offset;
208				int idx = addr & ((1 << abits) - 1);
209				SigSpec w_init = init_data.extract(i*mem.width, mem.width);
210				if (static_cells_map.count(addr) > 0)
211				{
212					data_read[idx] = static_cells_map[addr];
213					count_static++;
214				}
215				else if (static_only && (!keepdc || w_init.is_fully_def()))
216				{
217					data_read[idx] = w_init;
218				}
219				else
220				{
221					RTLIL::Cell *c;
222					auto ff_id = genid(mem.memid, "", addr);
223	
224					if (static_only) {
225						// non-static part is a ROM, we only reach this with keepdc
226						if (formal) {
227							c = module->addCell(ff_id, ID($ff));
228						} else {
229							c = module->addCell(ff_id, ID($dff));
230							c->parameters[ID::CLK_POLARITY] = RTLIL::Const(RTLIL::State::S1);
231							c->setPort(ID::CLK, RTLIL::SigSpec(RTLIL::State::S0));
232						}
233					} else if (async_wr) {
234						log_assert(formal); // General async write not implemented yet, checked against above
235						c = module->addCell(ff_id, ID($ff));
236					} else {
237						c = module->addCell(ff_id, ID($dff));
238						c->parameters[ID::CLK_POLARITY] = RTLIL::Const(refclock_pol);
239						c->setPort(ID::CLK, refclock);
240					}
241					c->parameters[ID::WIDTH] = mem.width;
242	
243					RTLIL::Wire *w_in = module->addWire(genid(mem.memid, "", addr, "$d"), mem.width);
244					data_reg_in[idx] = w_in;
245					c->setPort(ID::D, w_in);
246	
247					std::string w_out_name = stringf("%s[%d]", mem.memid, addr);
248					if (module->wires_.count(w_out_name) > 0)
249						w_out_name = genid(mem.memid, "", addr, "$q");
250	
251					RTLIL::Wire *w_out = module->addWire(w_out_name, mem.width);
252	
253					if (formal && mem.packed && mem.cell->name.c_str()[0] == '\\') {
254						auto hdlname = mem.cell->get_hdlname_attribute();
255						if (hdlname.empty())
256							hdlname.push_back(mem.cell->name.c_str() + 1);
257						hdlname.push_back(stringf("[%d]", addr));
258						w_out->set_hdlname_attribute(hdlname);
259					}
260	
261					if (!w_init.is_fully_undef())
262						w_out->attributes[ID::init] = w_init.as_const();
263	
264					data_reg_out[idx] = w_out;
265					c->setPort(ID::Q, w_out);
266	
267					if (static_only)
268						module->connect(RTLIL::SigSig(w_in, w_out));
269				}
270			}
271	
272			log("  created %d %s cells and %d static cells of width %d.\n",
273					mem.size-count_static, formal && (static_only || async_wr) ? "$ff" : "$dff", count_static, mem.width);
274	
275			int count_dff = 0, count_mux = 0, count_wrmux = 0;
276	
277			for (int i = 0; i < GetSize(mem.rd_ports); i++)
278			{
279				auto &port = mem.rd_ports[i];
280				if (mem.extract_rdff(i, &initvals))
281					count_dff++;
282				RTLIL::SigSpec rd_addr = port.addr;
283				rd_addr.extend_u0(abits, false);
284	
285				std::vector<RTLIL::SigSpec> rd_signals;
286				rd_signals.push_back(port.data);
287	
288				for (int j = 0; j < abits - port.wide_log2; j++)
289				{
290					std::vector<RTLIL::SigSpec> next_rd_signals;
291	
292					for (size_t k = 0; k < rd_signals.size(); k++)
293					{
294						RTLIL::Cell *c = module->addCell(genid(mem.memid, "$rdmux", i, "", j, "", k), ID($mux));
295						c->parameters[ID::WIDTH] = GetSize(port.data);
296						c->setPort(ID::Y, rd_signals[k]);
297						c->setPort(ID::S, rd_addr.extract(abits-j-1, 1));
298						count_mux++;
299	
300						c->setPort(ID::A, module->addWire(genid(mem.memid, "$rdmux", i, "", j, "", k, "$a"), GetSize(port.data)));
301						c->setPort(ID::B, module->addWire(genid(mem.memid, "$rdmux", i, "", j, "", k, "$b"), GetSize(port.data)));
302	
303						next_rd_signals.push_back(c->getPort(ID::A));
304						next_rd_signals.push_back(c->getPort(ID::B));
305					}
306	
307					next_rd_signals.swap(rd_signals);
308				}
309	
310				for (int j = 0; j < (1 << abits); j++)
311					if (data_read[j] != SigSpec())
312						module->connect(RTLIL::SigSig(rd_signals[j >> port.wide_log2].extract((j & ((1 << port.wide_log2) - 1)) * mem.width, mem.width), data_read[j]));
313			}
314	
315			log("  read interface: %d $dff and %d $mux cells.\n", count_dff, count_mux);
316	
317			if (!static_only)
318			{
319				for (int i = 0; i < mem.size; i++)
320				{
321					int addr = i + mem.start_offset;
322					int idx = addr & ((1 << abits) - 1);
323					if (static_cells_map.count(addr) > 0)
324						continue;
325	
326					RTLIL::SigSpec sig = data_reg_out[idx];
327	
328					for (int j = 0; j < GetSize(mem.wr_ports); j++)
329					{
330						auto &port = mem.wr_ports[j];
331						RTLIL::SigSpec wr_addr = port.addr.extract_end(port.wide_log2);
332						RTLIL::Wire *w_seladdr = addr_decode(wr_addr, RTLIL::SigSpec(addr >> port.wide_log2, GetSize(wr_addr)));
333	
334						int sub = addr & ((1 << port.wide_log2) - 1);
335	
336						int wr_offset = 0;
337						while (wr_offset < mem.width)
338						{
339							int wr_width = 1;
340							RTLIL::SigSpec wr_bit = port.en.extract(wr_offset + sub * mem.width, 1);
341	
342							while (wr_offset + wr_width < mem.width) {
343								RTLIL::SigSpec next_wr_bit = port.en.extract(wr_offset + wr_width + sub * mem.width, 1);
344								if (next_wr_bit != wr_bit)
345									break;
346								wr_width++;
347							}
348	
349							RTLIL::Wire *w = w_seladdr;
350	
351							if (wr_bit != State::S1)
352							{
353								RTLIL::Cell *c = module->addCell(genid(mem.memid, "$wren", addr, "", j, "", wr_offset), ID($and));
354								c->parameters[ID::A_SIGNED] = RTLIL::Const(0);
355								c->parameters[ID::B_SIGNED] = RTLIL::Const(0);
356								c->parameters[ID::A_WIDTH] = RTLIL::Const(1);
357								c->parameters[ID::B_WIDTH] = RTLIL::Const(1);
358								c->parameters[ID::Y_WIDTH] = RTLIL::Const(1);
359								c->setPort(ID::A, w);
360								c->setPort(ID::B, wr_bit);
361	
362								w = module->addWire(genid(mem.memid, "$wren", addr, "", j, "", wr_offset, "$y"));
363								c->setPort(ID::Y, RTLIL::SigSpec(w));
364							}
365	
366							RTLIL::Cell *c = module->addCell(genid(mem.memid, "$wrmux", addr, "", j, "", wr_offset), ID($mux));
367							c->parameters[ID::WIDTH] = wr_width;
368							c->setPort(ID::A, sig.extract(wr_offset, wr_width));
369							c->setPort(ID::B, port.data.extract(wr_offset + sub * mem.width, wr_width));
370							c->setPort(ID::S, RTLIL::SigSpec(w));
371	
372							w = module->addWire(genid(mem.memid, "$wrmux", addr, "", j, "", wr_offset, "$y"), wr_width);
373							c->setPort(ID::Y, w);
374	
375							sig.replace(wr_offset, w);
376							wr_offset += wr_width;
377							count_wrmux++;
378						}
379					}
380	
381					module->connect(RTLIL::SigSig(data_reg_in[idx], sig));
382				}
383			}
384	
385			log("  write interface: %d write mux blocks.\n", count_wrmux);
386	
387			mem.remove();
388		}
389	
390		void run()
391		{
392			for (auto &mem : Mem::get_selected_memories(module))
393				handle_memory(mem);
394		}
395	};
396	
397	struct MemoryMapPass : public Pass {
398		MemoryMapPass() : Pass("memory_map", "translate multiport memories to basic cells") { }
399		void help() override
400		{
401			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
402			log("\n");
403			log("    memory_map [options] [selection]\n");
404			log("\n");
405			log("This pass converts multiport memory cells as generated by the memory_collect\n");
406			log("pass to word-wide DFFs and address decoders.\n");
407			log("\n");
408			log("    -attr !<name>\n");
409			log("        do not map memories that have attribute <name> set.\n");
410			log("\n");
411			log("    -attr <name>[=<value>]\n");
412			log("        for memories that have attribute <name> set, only map them if its value\n");
413			log("        is a string <value> (if specified), or an integer 1 (otherwise). if this\n");
414			log("        option is specified multiple times, map the memory if the attribute is\n");
415			log("        to any of the values.\n");
416			log("\n");
417			log("    -iattr\n");
418			log("        for -attr, suppress case sensitivity in matching of <value>.\n");
419			log("\n");
420			log("    -rom-only\n");
421			log("        only perform conversion for ROMs (memories with no write ports).\n");
422			log("\n");
423			log("    -keepdc\n");
424			log("        when mapping ROMs, keep x-bits shared across read ports.\n");
425			log("\n");
426			log("    -formal\n");
427			log("        map memories for a global clock based formal verification flow.\n");
428			log("        This implies -keepdc, uses $ff cells for ROMs and sets hdlname\n");
429			log("        attributes. It also has limited support for async write ports\n");
430			log("        as generated by clk2fflogic.\n");
431			log("\n");
432		}
433		void execute(std::vector<std::string> args, RTLIL::Design *design) override
434		{
435			bool attr_icase = false;
436			bool rom_only = false;
437			bool keepdc = false;
438			bool formal = false;
439			dict<RTLIL::IdString, std::vector<RTLIL::Const>> attributes;
440	
441			log_header(design, "Executing MEMORY_MAP pass (converting memories to logic and flip-flops).\n");
442	
443			size_t argidx;
444			for (argidx = 1; argidx < args.size(); argidx++)
445			{
446				if (args[argidx] == "-attr" && argidx + 1 < args.size())
447				{
448					std::string attr_arg = args[++argidx];
449					std::string name;
450					RTLIL::Const value;
451					size_t eq_at = attr_arg.find('=');
452					if (eq_at != std::string::npos) {
453						name  = attr_arg.substr(0, eq_at);
454						value = attr_arg.substr(eq_at + 1);
455					} else {
456						name  = attr_arg;
457						value = RTLIL::Const(1);
458					}
459					if (attr_arg.size() > 1 && attr_arg[0] == '!') {
460						if (value != RTLIL::Const(1)) {
461							--argidx;
462							break; // we don't support -attr !<name>=<value>
463						}
464						attributes[RTLIL::escape_id(name.substr(1))].clear();
465					} else {
466						attributes[RTLIL::escape_id(name)].push_back(value);
467					}
468					continue;
469				}
470				if (args[argidx] == "-iattr")
471				{
472					attr_icase = true;
473					continue;
474				}
475				if (args[argidx] == "-rom-only")
476				{
477					rom_only = true;
478					continue;
479				}
480				if (args[argidx] == "-keepdc")
481				{
482					keepdc = true;
483					continue;
484				}
485				if (args[argidx] == "-formal")
486				{
487					formal = true;
488					keepdc = true;
489					continue;
490				}
491				break;
492			}
493			extra_args(args, argidx, design);
494	
495			for (auto mod : design->selected_modules()) {
496				if (mod->has_processes_warn())
497					continue;
498	
499				MemoryMapWorker worker(design, mod);
500				worker.attr_icase = attr_icase;
501				worker.attributes = attributes;
502				worker.rom_only = rom_only;
503				worker.keepdc = keepdc;
504				worker.formal = formal;
505				worker.run();
506			}
507		}
508	} MemoryMapPass;
509	
510	PRIVATE_NAMESPACE_END
