29	struct MemRd : RTLIL::AttrObject {
30		bool removed;
31		Cell *cell;
32		int wide_log2;
33		bool clk_enable, clk_polarity, ce_over_srst;
34		Const arst_value, srst_value, init_value;
35		// One bit for every write port, true iff simultanous read on this
36		// port and write on the other port will bypass the written data
37		// to this port's output (default behavior is to read old value).
38		// Can only be set for write ports that have the same clock domain.
39		std::vector<bool> transparency_mask;
40		// One bit for every write port, true iff simultanous read on this
41		// port and write on the other port will return an all-X (don't care)
42		// value.  Mutually exclusive with transparency_mask.
43		// Can only be set for write ports that have the same clock domain.
44		// For optimization purposes, this will also be set if we can
45		// determine that the two ports can never be active simultanously
46		// (making the above vacuously true).
47		std::vector<bool> collision_x_mask;
48		SigSpec clk, en, arst, srst, addr, data;
49	
50		MemRd() : removed(false), cell(nullptr), wide_log2(0), clk_enable(false), clk_polarity(true), ce_over_srst(false), clk(State::Sx), en(State::S1), arst(State::S0), srst(State::S0) {}
51	
52		// Returns the address of given subword index accessed by this port.
53		SigSpec sub_addr(int sub) {
54			SigSpec res = addr;
55			for (int i = 0; i < wide_log2; i++)
56				res[i] = State(sub >> i & 1);
57			return res;
58		}
59	};
