61	struct MemWr : RTLIL::AttrObject {
62		bool removed;
63		Cell *cell;
64		int wide_log2;
65		bool clk_enable, clk_polarity;
66		std::vector<bool> priority_mask;
67		SigSpec clk, en, addr, data;
68	
69		MemWr() : removed(false), cell(nullptr) {}
70	
71		// Returns the address of given subword index accessed by this port.
72		SigSpec sub_addr(int sub) {
73			SigSpec res = addr;
74			for (int i = 0; i < wide_log2; i++)
75				res[i] = State(sub >> i & 1);
76			return res;
77		}
78	
79		std::pair<SigSpec, std::vector<int>> compress_en();
