92	struct Mem : RTLIL::AttrObject {
93		Module *module;
94		IdString memid;
95		bool packed;
96		RTLIL::Memory *mem;
97		Cell *cell;
98		int width, start_offset, size;
99		std::vector<MemInit> inits;
100		std::vector<MemRd> rd_ports;
101		std::vector<MemWr> wr_ports;
102	
103		// Removes this memory from the module.  The data in helper structures
104		// is unaffected except for the cell/mem fields.
105		void remove();
106	
107		// Commits all changes in helper structures into the module — ports and
108		// inits marked as removed are actually removed, new ports/inits create
109		// new cells, modified port/inits are commited into their existing
110		// cells.  Note that this reindexes the ports and inits array (actually
111		// removing the ports/inits marked as removed).
112		void emit();
113	
114		// Marks all inits as removed.
115		void clear_inits();
116	
117		// Coalesces inits: whenever two inits have overlapping or touching
118		// address ranges, they are combined into one, with the higher-priority
119		// one's data overwriting the other.  Running this results in
120		// an inits list equivalent to the original, in which all entries
121		// cover disjoint (and non-touching) address ranges, and all enable
122		// masks are all-1.
123		void coalesce_inits();
124	
125		// Checks consistency of this memory and all its ports/inits, using
126		// log_assert.
127		void check();
128	
129		// Gathers all initialization data into a single big const covering
130		// the whole memory.  For all non-initialized bits, Sx will be returned.
131		Const get_init_data() const;
132	
133		// Constructs and returns the helper structures for all memories
134		// in a module.
135		static std::vector<Mem> get_all_memories(Module *module);
136	
137		// Constructs and returns the helper structures for all selected
138		// memories in a module.
139		static std::vector<Mem> get_selected_memories(Module *module);
140	
141		// Converts a synchronous read port into an asynchronous one by
142		// extracting the data (or, in some rare cases, address) register
143		// into a separate cell, together with any soft-transparency
144		// logic necessary to preserve its semantics.  Returns the created
145		// register cell, if any.  Note that in some rare cases this function
146		// may succeed and perform a conversion without creating a new
147		// register — a nullptr result doesn't imply nothing was done.
148		Cell *extract_rdff(int idx, FfInitVals *initvals);
149	
150		// Splits all wide ports in this memory into equivalent narrow ones.
151		// This function performs no modifications at all to the actual
152		// netlist unless and until emit() is called.
153		void narrow();
154	
155		// If write port idx2 currently has priority over write port idx1,
156		// inserts extra logic on idx1's enable signal to disable writes
157		// when idx2 is writing to the same address, then removes the priority
158		// from the priority mask.  If there is a memory port that is
159		// transparent with idx1, but not with idx2, that port is converted
160		// to use soft transparency logic.
161		void emulate_priority(int idx1, int idx2, FfInitVals *initvals);
162	
163		// Creates soft-transparency logic on read port ridx, bypassing the
164		// data from write port widx.  Should only be called when ridx is
165		// transparent wrt widx in the first place.  Once we're done, the
166		// transparency_mask bit will be cleared, and the collision_x_mask
167		// bit will be set instead (since whatever value is read will be
168		// replaced by the soft transparency logic).
169		void emulate_transparency(int widx, int ridx, FfInitVals *initvals);
170	
171		// Prepares for merging write port idx2 into idx1 (where idx1 < idx2).
172		// Specifically, takes care of priority masks: any priority relations
173		// that idx2 had are replicated onto idx1, unless they conflict with
174		// priorities already present on idx1, in which case emulate_priority
175		// is called.  Likewise, ensures transparency and undefined collision
176		// masks of all read ports have the same values for both ports,
177		// calling emulate_transparency if necessary.
178		void prepare_wr_merge(int idx1, int idx2, FfInitVals *initvals);
179	
180		// Prepares for merging read port idx2 into idx1.
181		// Specifically, makes sure the transparency and undefined collision
182		// masks of both ports are equal, by changing undefined behavior
183		// of one port to the other's defined behavior, or by calling
184		// emulate_transparency if necessary.
185		void prepare_rd_merge(int idx1, int idx2, FfInitVals *initvals);
186	
187		// Prepares the memory for widening a port to a given width.  This
188		// involves ensuring that start_offset and size are aligned to the
189		// target width.
190		void widen_prep(int wide_log2);
191	
192		// Widens a write port up to a given width.  The newly port is
193		// equivalent to the original, made by replicating enable/data bits
194		// and masking enable bits with decoders on the low part of the
195		// original address.
196		void widen_wr_port(int idx, int wide_log2);
197	
198		// Emulates a sync read port's enable functionality in soft logic,
199		// changing the actual read port's enable to be always-on.
200		void emulate_rden(int idx, FfInitVals *initvals);
201	
202		// Emulates a sync read port's initial/reset value functionality in
203		// soft logic, removing it from the actual read port.
204		void emulate_reset(int idx, bool emu_init, bool emu_arst, bool emu_srst, FfInitVals *initvals);
205	
206		// Given a read port with ce_over_srst set, converts it to a port
207		// with ce_over_srst unset without changing its behavior by adding
208		// emulation logic.
209		void emulate_rd_ce_over_srst(int idx);
210	
211		// Given a read port with ce_over_srst unset, converts it to a port
212		// with ce_over_srst set without changing its behavior by adding
213		// emulation logic.
214		void emulate_rd_srst_over_ce(int idx);
215	
216		// Returns true iff emulate_read_first makes sense to call.
217		bool emulate_read_first_ok();
218	
219		// Emulates all read-first read-write port relationships in terms of
220		// all-transparent ports, by delaying all write ports by one cycle.
221		// This can only be used when all read ports and all write ports are
222		// in the same clock domain.
223		void emulate_read_first(FfInitVals *initvals);
224	
225		Mem(Module *module, IdString memid, int width, int start_offset, int size) : module(module), memid(memid), packed(false), mem(nullptr), cell(nullptr), width(width), start_offset(start_offset), size(size) {}
226	};
