228	// MemContents efficiently represents the contents of a potentially sparse memory by storing only those segments that are actually defined
229	class MemContents {
230	public:
231		class range; class iterator;
232		using addr_t = uint32_t;
233	private:
234		// we ban _addr_width == sizeof(addr_t) * 8 because it adds too many cornercases
235		int _addr_width;
236		int _data_width;
237		RTLIL::Const _default_value;
238		// for each range, store the concatenation of the words at the start address
239		// invariants:
240		// - no overlapping or adjacent ranges
241		// - no empty ranges
242		// - all Consts are a multiple of the word size
243		std::map<addr_t, RTLIL::Const> _values;
244		// returns an iterator to the range containing addr, if it exists, or the first range past addr
245		std::map<addr_t, RTLIL::Const>::iterator _range_at(addr_t addr) const;
246		addr_t _range_size(std::map<addr_t, RTLIL::Const>::iterator it) const { return it->second.size() / _data_width; }
247		addr_t _range_begin(std::map<addr_t, RTLIL::Const>::iterator it) const { return it->first; }
248		addr_t _range_end(std::map<addr_t, RTLIL::Const>::iterator it) const { return _range_begin(it) + _range_size(it); }
249		// check if the iterator points to a range containing addr
250		bool _range_contains(std::map<addr_t, RTLIL::Const>::iterator it, addr_t addr) const;
251		// check if the iterator points to a range containing [begin_addr, end_addr). assumes end_addr >= begin_addr.
252		bool _range_contains(std::map<addr_t, RTLIL::Const>::iterator it, addr_t begin_addr, addr_t end_addr) const;
253		// check if the iterator points to a range overlapping with [begin_addr, end_addr)
254		bool _range_overlaps(std::map<addr_t, RTLIL::Const>::iterator it, addr_t begin_addr, addr_t end_addr) const;
255		// return the offset the addr would have in the range at `it`
256		size_t _range_offset(std::map<addr_t, RTLIL::Const>::iterator it, addr_t addr) const { return (addr - it->first) * _data_width; }
257		// assuming _range_contains(it, addr), return an iterator pointing to the data at addr
258		RTLIL::Const::iterator _range_data(std::map<addr_t, RTLIL::Const>::iterator it, addr_t addr) {
259			return RTLIL::Const::iterator(it->second, _range_offset(it, addr));
260		}
261		// internal version of reserve_range that returns an iterator to the range
262		std::map<addr_t, RTLIL::Const>::iterator _reserve_range(addr_t begin_addr, addr_t end_addr);
263		// write a single word at addr, return iterator to next word
264		RTLIL::Const::iterator _range_write(RTLIL::Const::iterator it, RTLIL::Const const &data);
265	public:
266		class range {
267			int _data_width;
268			addr_t _base;
269			RTLIL::Const const &_values;
270			friend class iterator;
271			range(int data_width, addr_t base, RTLIL::Const const &values)
272			: _data_width(data_width), _base(base), _values(values) {}
273		public:
274			addr_t base() const { return _base; }
275			addr_t size() const { return ((addr_t) _values.size()) / _data_width; }
276			addr_t limit() const { return _base + size(); }
277			RTLIL::Const const &concatenated() const { return _values; }
278			RTLIL::Const operator[](addr_t addr) const {
279				log_assert(addr - _base < size());
280				return _values.extract((addr - _base) * _data_width, _data_width);
281			}
282			RTLIL::Const at_offset(addr_t offset) const { return (*this)[_base + offset]; }
283		};
284		class iterator {
285			MemContents const *_memory;
286			// storing addr instead of an iterator gives more well-defined behaviour under insertions/deletions
287			// use ~0 for end so that all end iterators compare the same
288			addr_t _addr;
289			friend class MemContents;
290			iterator(MemContents const *memory, addr_t addr) : _memory(memory), _addr(addr) {}
291		public:
292			using iterator_category = std::input_iterator_tag;
293			using value_type = range;
294			using pointer = arrow_proxy<range>;
295			using reference = range;
296			using difference_type = addr_t;
297			reference operator *() const { return range(_memory->_data_width, _addr, _memory->_values.at(_addr)); }
298			pointer operator->() const { return arrow_proxy<range>(**this); }
299			bool operator !=(iterator const &other) const { return _memory != other._memory || _addr != other._addr; }
300			bool operator ==(iterator const &other) const { return !(*this != other); }
301			iterator &operator++();
302		};
303		MemContents(int addr_width, int data_width, RTLIL::Const default_value)
304			: _addr_width(addr_width), _data_width(data_width)
305			, _default_value((default_value.extu(data_width), std::move(default_value)))
306		{ log_assert(_addr_width > 0 && _addr_width < (int)sizeof(addr_t) * 8); log_assert(_data_width > 0); }
307		MemContents(int addr_width, int data_width) : MemContents(addr_width, data_width, RTLIL::Const(State::Sx, data_width)) {}
308		explicit MemContents(Mem *mem);
309		int addr_width() const { return _addr_width; }
310		int data_width() const { return _data_width; }
311		RTLIL::Const const &default_value() const { return _default_value; }
312		// return the value at the address if it exists, the default_value of the memory otherwise. address must not exceed 2**addr_width.
313		RTLIL::Const operator [](addr_t addr) const;
314		// return the number of defined words in the range [begin_addr, end_addr)
315		addr_t count_range(addr_t begin_addr, addr_t end_addr) const;
316		// allocate memory for the range [begin_addr, end_addr), but leave the contents undefined.
317		void reserve_range(addr_t begin_addr, addr_t end_addr) { _reserve_range(begin_addr, end_addr); }
318		// insert multiple words (provided as a single concatenated RTLIL::Const) at the given address, overriding any previous assignment.
319		void insert_concatenated(addr_t addr, RTLIL::Const const &values);
320		// insert multiple words at the given address, overriding any previous assignment.
321		template<typename Iterator> void insert_range(addr_t addr, Iterator begin, Iterator end) {
322			auto words = end - begin;
323			log_assert(addr < (addr_t)(1<<_addr_width)); log_assert(words <= (addr_t)(1<<_addr_width) - addr);
324			auto range = _reserve_range(addr, addr + words);
325			auto it = _range_data(range, addr);
326			for(; begin != end; ++begin)
327				it = _range_write(it, *begin);
328		}
329		// undefine all words in the range [begin_addr, end_addr)
330		void clear_range(addr_t begin_addr, addr_t end_addr);
331		// check invariants, abort if invariants failed
332		void check();
333		iterator end() const { return iterator(nullptr, ~(addr_t) 0); }
334		iterator begin() const { return _values.empty() ? end() : iterator(this, _values.begin()->first); }
335		bool empty() const { return _values.empty(); }
336	};
337	
338	YOSYS_NAMESPACE_END
339	
340	#endif
