25	void Mem::remove() {
26		if (cell) {
27			module->remove(cell);
28			cell = nullptr;
29		}
30		if (mem) {
31			module->memories.erase(mem->name);
32			delete mem;
33			mem = nullptr;
34		}
35		for (auto &port : rd_ports) {
36			if (port.cell) {
37				module->remove(port.cell);
38				port.cell = nullptr;
39			}
40		}
41		for (auto &port : wr_ports) {
42			if (port.cell) {
43				module->remove(port.cell);
44				port.cell = nullptr;
45			}
46		}
47		for (auto &init : inits) {
48			if (init.cell) {
49				module->remove(init.cell);
50				init.cell = nullptr;
51			}
52		}
53	}
54	
55	void Mem::emit() {
56		check();
57		std::vector<int> rd_left;
58		for (int i = 0; i < GetSize(rd_ports); i++) {
59			auto &port = rd_ports[i];
60			if (port.removed) {
61				if (port.cell) {
62					module->remove(port.cell);
63				}
64			} else {
65				rd_left.push_back(i);
66			}
67		}
68		std::vector<int> wr_left;
69		for (int i = 0; i < GetSize(wr_ports); i++) {
70			auto &port = wr_ports[i];
71			if (port.removed) {
72				if (port.cell) {
73					module->remove(port.cell);
74				}
75			} else {
76				wr_left.push_back(i);
77			}
78		}
79		std::vector<int> init_left;
80		for (int i = 0; i < GetSize(inits); i++) {
81			auto &init = inits[i];
82			if (init.removed) {
83				if (init.cell) {
84					module->remove(init.cell);
85				}
86			} else {
87				init_left.push_back(i);
88			}
89		}
90		for (int i = 0; i < GetSize(rd_left); i++)
91			if (i != rd_left[i])
92				std::swap(rd_ports[i], rd_ports[rd_left[i]]);
93		rd_ports.resize(GetSize(rd_left));
94		for (int i = 0; i < GetSize(wr_left); i++)
95			if (i != wr_left[i])
96				std::swap(wr_ports[i], wr_ports[wr_left[i]]);
97		wr_ports.resize(GetSize(wr_left));
98		for (int i = 0; i < GetSize(init_left); i++)
99			if (i != init_left[i])
100				std::swap(inits[i], inits[init_left[i]]);
101		inits.resize(GetSize(init_left));
102	
103		for (auto &port : rd_ports) {
104			for (int i = 0; i < GetSize(wr_left); i++) {
105				port.transparency_mask[i] = port.transparency_mask[wr_left[i]];
106				port.collision_x_mask[i] = port.collision_x_mask[wr_left[i]];
107			}
108			port.transparency_mask.resize(GetSize(wr_left));
109			port.collision_x_mask.resize(GetSize(wr_left));
110		}
111		for (auto &port : wr_ports) {
112			for (int i = 0; i < GetSize(wr_left); i++)
113				port.priority_mask[i] = port.priority_mask[wr_left[i]];
114			port.priority_mask.resize(GetSize(wr_left));
115		}
116	
117		if (packed) {
118			if (mem) {
119				module->memories.erase(mem->name);
120				delete mem;
121				mem = nullptr;
122			}
123			if (!cell) {
124				if (memid.empty())
125					memid = NEW_ID;
126				cell = module->addCell(memid, ID($mem_v2));
127			}
128			cell->type = ID($mem_v2);
129			cell->attributes = attributes;
130			cell->parameters[ID::MEMID] = Const(memid.str());
131			cell->parameters[ID::WIDTH] = Const(width);
132			cell->parameters[ID::OFFSET] = Const(start_offset);
133			cell->parameters[ID::SIZE] = Const(size);
134			SigSpec rd_clk, rd_en, rd_addr, rd_data;
135			SigSpec wr_clk, wr_en, wr_addr, wr_data;
136			SigSpec rd_arst, rd_srst;
137			int abits = 0;
138			for (auto &port : rd_ports)
139				abits = std::max(abits, GetSize(port.addr));
140			for (auto &port : wr_ports)
141				abits = std::max(abits, GetSize(port.addr));
142			cell->parameters[ID::ABITS] = Const(abits);
143			std::vector<int> wr_port_xlat;
144			for (int i = 0; i < GetSize(wr_ports); i++)
145				for (int j = 0; j < (1 << wr_ports[i].wide_log2); j++)
146					wr_port_xlat.push_back(i);
147			Const::Builder rd_wide_continuation_builder;
148			Const::Builder rd_clk_enable_builder;
149			Const::Builder rd_clk_polarity_builder;
150			Const::Builder rd_transparency_mask_builder;
151			Const::Builder rd_collision_x_mask_builder;
152			Const::Builder rd_ce_over_srst_builder;
153			Const::Builder rd_arst_value_builder;
154			Const::Builder rd_srst_value_builder;
155			Const::Builder rd_init_value_builder;
156			for (auto &port : rd_ports) {
157				for (auto attr: port.attributes)
158					if (!cell->has_attribute(attr.first))
159						cell->attributes.insert(attr);
160				if (port.cell) {
161					module->remove(port.cell);
162					port.cell = nullptr;
163				}
164				for (int sub = 0; sub < (1 << port.wide_log2); sub++)
165				{
166					rd_wide_continuation_builder.push_back(State(sub != 0));
167					rd_clk_enable_builder.push_back(State(port.clk_enable));
168					rd_clk_polarity_builder.push_back(State(port.clk_polarity));
169					rd_ce_over_srst_builder.push_back(State(port.ce_over_srst));
170					rd_clk.append(port.clk);
171					rd_arst.append(port.arst);
172					rd_srst.append(port.srst);
173					rd_en.append(port.en);
174					SigSpec addr = port.sub_addr(sub);
175					addr.extend_u0(abits, false);
176					rd_addr.append(addr);
177					log_assert(GetSize(addr) == abits);
178					for (auto idx : wr_port_xlat) {
179						rd_transparency_mask_builder.push_back(State(bool(port.transparency_mask[idx])));
180						rd_collision_x_mask_builder.push_back(State(bool(port.collision_x_mask[idx])));
181					}
182				}
183				rd_data.append(port.data);
184				for (auto bit : port.arst_value)
185					rd_arst_value_builder.push_back(bit);
186				for (auto bit : port.srst_value)
187					rd_srst_value_builder.push_back(bit);
188				for (auto bit : port.init_value)
189					rd_init_value_builder.push_back(bit);
190			}
191			Const rd_wide_continuation = rd_wide_continuation_builder.build();
192			Const rd_clk_enable = rd_clk_enable_builder.build();
193			Const rd_clk_polarity = rd_clk_polarity_builder.build();
194			Const rd_transparency_mask = rd_transparency_mask_builder.build();
195			Const rd_collision_x_mask = rd_collision_x_mask_builder.build();
196			Const rd_ce_over_srst = rd_ce_over_srst_builder.build();
197			Const rd_arst_value = rd_arst_value_builder.build();
198			Const rd_srst_value = rd_srst_value_builder.build();
199			Const rd_init_value = rd_init_value_builder.build();
200			if (rd_ports.empty()) {
201				rd_wide_continuation = State::S0;
202				rd_clk_enable = State::S0;
203				rd_clk_polarity = State::S0;
204				rd_ce_over_srst = State::S0;
205				rd_arst_value = State::S0;
206				rd_srst_value = State::S0;
207				rd_init_value = State::S0;
208			}
209			if (rd_ports.empty() || wr_ports.empty()) {
210				rd_transparency_mask = State::S0;
211				rd_collision_x_mask = State::S0;
212			}
213			cell->parameters[ID::RD_PORTS] = Const(GetSize(rd_clk));
214			cell->parameters[ID::RD_CLK_ENABLE] = rd_clk_enable;
215			cell->parameters[ID::RD_CLK_POLARITY] = rd_clk_polarity;
216			cell->parameters[ID::RD_TRANSPARENCY_MASK] = rd_transparency_mask;
217			cell->parameters[ID::RD_COLLISION_X_MASK] = rd_collision_x_mask;
218			cell->parameters[ID::RD_WIDE_CONTINUATION] = rd_wide_continuation;
219			cell->parameters[ID::RD_CE_OVER_SRST] = rd_ce_over_srst;
220			cell->parameters[ID::RD_ARST_VALUE] = rd_arst_value;
