32	void proc_memwr(RTLIL::Module *mod, RTLIL::Process *proc, dict<IdString, int> &next_port_id)
33	{
34		for (auto sr : proc->syncs)
35		{
36			std::vector<int> prev_port_ids;
37			for (auto memwr : sr->mem_write_actions) {
38				int port_id = next_port_id[memwr.memid]++;
39				Const priority_mask(State::S0, port_id);
40				for (int i = 0; i < GetSize(prev_port_ids); i++)
41					if (memwr.priority_mask[i] == State::S1)
42						priority_mask.set(prev_port_ids[i], State::S1);
43				prev_port_ids.push_back(port_id);
44	
45				RTLIL::Cell *cell = mod->addCell(NEW_ID, ID($memwr_v2));
46				cell->attributes = memwr.attributes;
47				cell->setParam(ID::MEMID, Const(memwr.memid.str()));
48				cell->setParam(ID::ABITS, GetSize(memwr.address));
49				cell->setParam(ID::WIDTH, GetSize(memwr.data));
50				cell->setParam(ID::PORTID, port_id);
51				cell->setParam(ID::PRIORITY_MASK, priority_mask);
52				cell->setPort(ID::ADDR, memwr.address);
53				cell->setPort(ID::DATA, memwr.data);
54				SigSpec enable = memwr.enable;
55				for (auto sr2 : proc->syncs) {
56					if (sr2->type == RTLIL::SyncType::ST0) {
57						log_assert(sr2->mem_write_actions.empty());
58						enable = mod->Mux(NEW_ID, Const(State::S0, GetSize(enable)), enable, sr2->signal);
59					} else if (sr2->type == RTLIL::SyncType::ST1) {
60						log_assert(sr2->mem_write_actions.empty());
61						enable = mod->Mux(NEW_ID, enable, Const(State::S0, GetSize(enable)), sr2->signal);
62					}
